import React, { useState } from 'react';
import { FiBriefcase, FiGlobe } from 'react-icons/fi';

const Experience = () => {
  const workItems = [
    {
      company: 'ABC Engineering Firm',
      logo: '',
      roles: [
        {
          title: 'Senior Civil / Project Engineer',
          date: '2020 - Present',
          details: [
            'Coordinated consultants, contractors, inspectors, and internal teams during active civil works.',
            'Prepared RFIs, technical submissions, site instructions, drawing markups, and change records.',
            'Maintained quantity reviews, progress updates, cost trackers, and package-level reporting.',
          ],
          tags: ['Project Controls', 'Site Coordination'],
        },
        {
          title: 'Civil Engineer',
          date: '2018 - 2020',
          details: [
            'Supported roads, drainage, utility, and public works scopes from documentation through site closeout.',
            'Carried out QA/QC checks, inspection summaries, permit notes, and field reports.',
          ],
          tags: ['QA/QC', 'Public Works'],
        },
      ],
    },
    {
      company: 'XYZ Infrastructure',
      logo: '',
      roles: [
        {
          title: 'Graduate Civil Engineer',
          date: '2016 - 2018',
          details: [
            'Assisted with AutoCAD drawings, calculation packs, schedules, and design review notes.',
            'Produced quantity takeoffs and comparison sheets for tender and procurement support.',
            'Joined site walks to compare construction progress against drawings and specifications.',
          ],
          tags: ['AutoCAD', 'Takeoffs'],
        },
      ],
    },
  ];

  const educationItems = [
    {
      company: 'University / Polytechnic Name',
      logo: '',
      roles: [
        {
          title: 'Civil Engineering',
          date: '2012 - 2016',
          details: [
            'Focused on structural analysis, construction materials, transportation, geotechnical, and project management coursework.',
            'Completed design studio and capstone work involving drawings, calculations, and technical presentation.',
          ],
        },
      ],
    },
  ];

  const [activeTimeline, setActiveTimeline] = useState('work');
  const activeItems = activeTimeline === 'work' ? workItems : educationItems;

  return (
    <section id="experience" className="section featured-experience">
      <div className="container">
        <div className="section-heading">
          <span className="eyebrow">Featured Experience</span>
          <h2>Civil Works, Project Delivery, and Construction Coordination</h2>
          <p>
            A focused record of delivering technical work packages, coordinating field teams,
            and keeping infrastructure projects moving with disciplined controls.
          </p>
        </div>

        <div className="timeline-tabs" role="tablist" aria-label="Experience timeline">
          <button
            type="button"
            className={activeTimeline === 'work' ? 'active' : ''}
            onClick={() => setActiveTimeline('work')}
            role="tab"
            aria-selected={activeTimeline === 'work'}
          >
            Work
          </button>
          <button
            type="button"
            className={activeTimeline === 'education' ? 'active' : ''}
            onClick={() => setActiveTimeline('education')}
            role="tab"
            aria-selected={activeTimeline === 'education'}
          >
            Education
          </button>
        </div>

        <div className="experience-timeline">
          {activeItems.map((item) => (
            <article className="experience-item" key={item.company}>
              <div className="experience-rail" aria-hidden="true">
                <div className="experience-logo">
                  {item.logo ? (
                    <img src={item.logo} alt={`${item.company} logo`} />
                  ) : (
                    <FiBriefcase aria-hidden="true" />
                  )}
                </div>
              </div>
              <div className="experience-card">
                <h3>{item.company}</h3>
                {item.roles.map((role) => (
                  <div className="timeline-role" key={`${item.company}-${role.title}`}>
                    <div className="role-meta">
                      <p className="company">{role.title}</p>
                      <p className="date">{role.date}</p>
                    </div>
                    <ul className="achievement-list">
                      {role.details.map((detail) => (
                        <li key={detail}>{detail}</li>
                      ))}
                    </ul>
                    {role.tags && (
                      <div className="timeline-tags">
                        {role.tags.map((tag) => (
                          <span key={tag}><FiGlobe aria-hidden="true" /> {tag}</span>
                        ))}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Experience;
